// src/components/CouponForm/index.jsx

import React from 'react';
import { useForm } from 'react-hook-form';
import { BASE_URL } from '../../utils/api';
// Импортируем стили из MainPage.module.css через проп className
// import s from './CouponForm.module.css'; // ЭТОТ ФАЙЛ БОЛЬШЕ НЕ НУЖЕН
import Button from '../UI/Button';

// Компонент теперь принимает className для стилизации из MainPage.module.css
const CouponForm = ({ className }) => { 
  const { 
    register, 
    handleSubmit, 
    formState: { errors },
    reset 
  } = useForm();

  const onSubmit = async (data) => {
    try {
      // Обновляем тело запроса для отправки всех трех полей
      const response = await fetch(`${BASE_URL}/sale/send`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        // Отправляем все данные, включая Name и Email (если они нужны на бэкенде)
        body: JSON.stringify({ 
            name: data.name, 
            phone: data.phone,
            email: data.email 
        }),
      });

      if (response.ok) {
        alert('Спасибо! Ваш купон на скидку отправлен.');
        reset(); 
      } else {
        alert('Ошибка при отправке заявки.');
      }
    } catch (error) {
      console.error('Ошибка сети:', error);
      alert('Ошибка соединения с сервером.');
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className={className}>

        {/* 1. NAME FIELD */}
        <input
            type="text"
            placeholder="Name"
            {...register('name', { 
                required: 'Введите имя',
            })}
        />
        {errors.name && <p className="error">{errors.name.message}</p>}

        {/* 2. PHONE NUMBER FIELD */}
        <input
            type="tel"
            placeholder="Phone number"
            {...register('phone', { 
                required: 'Введите номер телефона',
                // Уточненная формула для номера
                pattern: {
                    value: /^\+?[0-9\s-()]{7,20}$/,
                    message: 'Некорректный формат телефона'
                }
            })}
        />
        {errors.phone && <p className="error">{errors.phone.message}</p>}

        {/* 3. EMAIL FIELD */}
        <input
            type="email" // Правильный тип для email
            placeholder="Email"
            {...register('email', { 
                required: 'Введите email',
                pattern: {
                    value: /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i, // Формула для email
                    message: 'Некорректный формат email'
                }
            })}
        />
        {errors.email && <p className="error">{errors.email.message}</p>}

        {/* Кнопка должна использовать класс из MainPage.module.css */}
        <button type="submit">
          Get a discount
        </button>

    </form>
  );
};

export default CouponForm;
